/**
 * WhatLoll.Encoder - JavaScript библиотека для шифрования и дешифрования текста
 * Версия: 2.2.0
 * Совместимость: Node.js, Browser, Deno, Bun
 */

class WhatLollEncoder {
    constructor() {
        // Версии шифрования
        this.V1 = 'v1';
        this.V2 = 'v2';
        
        // Инициализация таблиц
        this._initMaps();
    }
    
    _initMaps() {
        // ===== V1 Tables =====
        this.encryptMapV1 = new Map([
            ['а', 'б'], ['б', 'в'], ['в', 'г'], ['г', 'д'], ['д', 'е'],
            ['е', 'е1'], ['ё', 'е2'], ['ж', 'з'], ['з', 'и'], ['и', 'и1'],
            ['й', 'и2'], ['к', 'л'], ['л', 'м'], ['м', 'н'], ['н', '6'],
            ['о', '0'], ['п', 'π'], ['р', 'п'], ['с', 'ß'], ['т', 'у'],
            ['у', 'ф'], ['ф', 'х'], ['х', 'ц'], ['ц', 'ч'], ['ч', 'ш'],
            ['ш', 'щ'], ['щ', '_'], ['ь', '?'], ['ъ', '?'], ['ы', '?'],
            ['э', 'ю'], ['ю', 'я'], ['я', '_']
        ]);
        
        // ===== V2 Tables (обновленная) =====
        this.encryptMapV2 = new Map([
            // Русские буквы
            ['а', 'б'], ['б', 'в'], ['в', 'г'], ['г', 'д'], ['д', 'е'],
            ['е', 'е1'], ['ё', 'е2'], ['ж', 'з'], ['з', 'и'], ['и', 'и1'],
            ['й', 'и2'], ['к', 'л'], ['л', 'м'], ['м', 'н'], ['н', '6'],
            ['о', '0'], ['п', 'π'], ['р', 'п'], ['с', 'ß'], ['т', 'у'],
            ['у', 'ф'], ['ф', 'х'], ['х', 'ц'], ['ц', 'ч'], ['ч', 'ш'],
            ['ш', 'щ'], ['щ', '_'],
            
            // Уникальные коды для ь/ъ/ы
            ['ь', 'b'],
            ['ъ', '-b'],
            ['ы', 'bI'],
            
            ['э', 'ю'], ['ю', 'я'], ['я', '_'],
            
            // Пробел
            [' ', '_/'],
            
            // Английские буквы
            ['a', 'А'], ['b', 'йу'], ['c', 'ц'], ['d', 'дъ'], ['e', 'и3'],
            ['f', '2ф'], ['g', 'жъ'], ['h', 'Н'], ['i', '8и'], ['j', 'жъй'],
            ['k', '4а'], ['l', 'm'], ['m', ':'], ['n', 'h'], ['o', '0E'],
            ['p', 'ПE'], ['q', '4у'], ['r', '0p'], ['s', '2'], ['t', '!'],
            ['u', '%E'], ['v', '(w-v)'], ['w', '(v+v)'], ['x', '1'], ['y', '2'], ['z', '3']
        ]);
        
        // Создаем обратные таблицы для дешифрования
        this._createDecryptMaps();
    }
    
    _createDecryptMaps() {
        // V1 Decrypt Map
        this.decryptMapV1 = new Map();
        for (let [key, value] of this.encryptMapV1) {
            if (!this.decryptMapV1.has(value)) {
                this.decryptMapV1.set(value, key);
            }
        }
        
        // V2 Decrypt Map
        this.decryptMapV2 = new Map();
        for (let [key, value] of this.encryptMapV2) {
            if (!this.decryptMapV2.has(value)) {
                this.decryptMapV2.set(value, key);
            }
        }
    }
    
    /**
     * Шифрование текста
     * @param {string} input - Входной текст
     * @param {string} version - Версия ('v1' или 'v2')
     * @returns {string} Зашифрованный текст
     */
    encrypt(input, version = 'v2') {
        if (!input || typeof input !== 'string') return input;
        
        const map = version === 'v1' ? this.encryptMapV1 : this.encryptMapV2;
        let result = '';
        
        for (let char of input) {
            const lowerChar = char.toLowerCase();
            
            if (map.has(lowerChar)) {
                result += map.get(lowerChar);
            } else if (map.has(char)) {
                result += map.get(char);
            } else {
                result += char; // спецсимволы пропускаем
            }
        }
        
        return result;
    }
    
    /**
     * Шифрование V1
     * @param {string} input - Входной текст
     * @returns {string} Зашифрованный текст
     */
    encryptV1(input) {
        return this.encrypt(input, 'v1');
    }
    
    /**
     * Шифрование V2 (рекомендуется)
     * @param {string} input - Входной текст
     * @returns {string} Зашифрованный текст
     */
    encryptV2(input) {
        return this.encrypt(input, 'v2');
    }
    
    /**
     * Дешифрование текста
     * @param {string} input - Зашифрованный текст
     * @param {string} version - Версия ('v1' или 'v2')
     * @returns {string} Расшифрованный текст
     */
    decrypt(input, version = 'v2') {
        if (!input || typeof input !== 'string') return input;
        
        const map = version === 'v1' ? this.decryptMapV1 : this.decryptMapV2;
        let result = '';
        let i = 0;
        
        while (i < input.length) {
            let found = false;
            
            // Проверяем длинные комбинации (до 5 символов)
            for (let len = 5; len >= 2; len--) {
                if (i + len <= input.length) {
                    const multiChars = input.substr(i, len);
                    if (map.has(multiChars)) {
                        result += map.get(multiChars);
                        i += len;
                        found = true;
                        break;
                    }
                }
            }
            
            // Проверяем двухсимвольные
            if (!found && i < input.length - 1) {
                const twoChars = input.substr(i, 2);
                if (map.has(twoChars)) {
                    result += map.get(twoChars);
                    i += 2;
                    found = true;
                }
            }
            
            // Проверяем односимвольные
            if (!found) {
                const oneChar = input[i];
                
                // Специальная обработка для '?'
                if (oneChar === '?') {
                    result += 'ь'; // по умолчанию
                } else if (map.has(oneChar)) {
                    result += map.get(oneChar);
                } else {
                    result += oneChar;
                }
                i++;
            }
        }
        
        return result;
    }
    
    /**
     * Дешифрование V1
     * @param {string} input - Зашифрованный текст
     * @returns {string} Расшифрованный текст
     */
    decryptV1(input) {
        return this.decrypt(input, 'v1');
    }
    
    /**
     * Дешифрование V2
     * @param {string} input - Зашифрованный текст
     * @returns {string} Расшифрованный текст
     */
    decryptV2(input) {
        return this.decrypt(input, 'v2');
    }
    
    /**
     * Автоопределение версии и дешифрование
     * @param {string} input - Зашифрованный текст
     * @returns {string} Расшифрованный текст
     */
    decryptAuto(input) {
        if (!input || typeof input !== 'string') return input;
        
        // Сначала пробуем V2
        const resultV2 = this.decryptV2(input);
        const resultV1 = this.decryptV1(input);
        
        // Если результаты отличаются, проверяем паттерны V2
        if (resultV2 !== resultV1) {
            const v2Patterns = ['-b', 'bI', '(w-v)', '(v+v)', 'йу', 'дъ', 'жъ', '0E', 'ПE', '%E'];
            for (let pattern of v2Patterns) {
                if (input.includes(pattern)) {
                    return resultV2;
                }
            }
        }
        
        return resultV1;
    }
    
    /**
     * Получить таблицу шифрования
     * @param {string} version - Версия ('v1' или 'v2')
     * @returns {string} Таблица шифрования
     */
    getEncryptionTable(version = 'v2') {
        const map = version === 'v1' ? this.encryptMapV1 : this.encryptMapV2;
        const mapArray = Array.from(map.entries());
        
        let table = `WhatLoll V${version.toUpperCase()} Таблица шифрования:\n`;
        table += '========================================\n\n';
        
        // Группируем по категориям для V2
        if (version === 'v2') {
            const russian = mapArray.filter(([key]) => 
                (key >= 'а' && key <= 'я') || key === 'ё' || key === 'ь' || key === 'ъ' || key === 'ы'
            ).sort(([a], [b]) => a.localeCompare(b));
            
            const english = mapArray.filter(([key]) => 
                key >= 'a' && key <= 'z'
            ).sort(([a], [b]) => a.localeCompare(b));
            
            table += 'РУССКИЕ БУКВЫ:\n';
            russian.forEach(([key, value]) => {
                table += `  '${key}' -> '${value}'\n`;
            });
            
            table += '\nАНГЛИЙСКИЕ БУКВЫ:\n';
            english.forEach(([key, value]) => {
                table += `  '${key}' -> '${value}'\n`;
            });
            
            table += '\nСПЕЦИАЛЬНЫЕ:\n';
            table += "  пробел -> '_/'\n";
        } else {
            mapArray.sort(([a], [b]) => a.localeCompare(b)).forEach(([key, value]) => {
                table += `  '${key}' -> '${value}'\n`;
            });
        }
        
        return table;
    }
    
    /**
     * Проверить поддержку символа
     * @param {string} char - Символ
     * @param {string} version - Версия
     * @returns {boolean}
     */
    isCharacterSupported(char, version = 'v2') {
        if (!char || char.length !== 1) return false;
        const map = version === 'v1' ? this.encryptMapV1 : this.encryptMapV2;
        return map.has(char.toLowerCase()) || map.has(char);
    }
    
    /**
     * Количество поддерживаемых символов
     * @param {string} version - Версия
     * @returns {number}
     */
    supportedCharactersCount(version = 'v2') {
        const map = version === 'v1' ? this.encryptMapV1 : this.encryptMapV2;
        return map.size;
    }
}

// Создаем экземпляр для удобства использования
const whatloll = new WhatLollEncoder();

// Экспорт для разных сред
if (typeof module !== 'undefined' && module.exports) {
    // Node.js
    module.exports = whatloll;
    module.exports.WhatLollEncoder = WhatLollEncoder;
} else if (typeof define === 'function' && define.amd) {
    // AMD
    define([], () => whatloll);
} else {
    // Browser
    window.whatloll = whatloll;
    window.WhatLollEncoder = WhatLollEncoder;
}